{# src/prompts/user.jinja2 #}
Answer the following question using only the provided context.

Context:
{% for chunk in context_chunks %}
---
{{ chunk.text }}
{% endfor %}

Question: {{ user_question }}

If the context does not contain enough information to answer the question,
respond with: "I don't have enough information to answer that."

# src/models/prompt_loader.py
from pathlib import Path
from jinja2 import Environment, FileSystemLoader

_PROMPT_DIR = Path(__file__).parent.parent / "prompts"
_jinja_env = Environment(loader=FileSystemLoader(_PROMPT_DIR))

def load_system_prompt() -> str:
    return (_PROMPT_DIR / "system.txt").read_text().strip()

def render_user_prompt(template_name: str, **vars) -> str:
    template = _jinja_env.get_template(template_name)
    return template.render(**vars)

# infra/terraform/main.tf
terraform {
  required_providers {
    google = { source = "hashicorp/google", version = "~> 5.0" }
  }
  backend "gcs" {
    bucket = "myorg-tf-state"
    prefix = "genai/my-genai-service"
  }
}

module "env" {
  source     = "git::https://github.com/myorg/platform-modules//genai-env?ref=v2.1.0"
  env_name   = var.env_name
  owner_team = "team-alpha"
  gpu_class  = var.gpu_class
  llm_models = ["gpt-4o", "claude-3-5-sonnet"]
  ttl_days   = var.ttl_days
  project_id = var.project_id
}
